Rule.Source:
  import java.util.List;

  import sailpoint.api.SailPointContext;
  import sailpoint.object.Bundle;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Util;


  public String cleanUpRoles(String roleNamesInCSV)
  {

    List roleNameList = Util.csvToList(roleNamesInCSV);
    List rolesNotFound = new ArrayList();
    String error = "";
    for (String roleName : roleNameList)
    {
      try
      {
        Bundle role = context.getObjectByName(Bundle.class, roleName);
        if (role == null)
        {
          rolesNotFound.add(roleName);
          continue;
        }
        context.removeObject(role);
        context.commitTransaction();
      }
      catch (GeneralException e)
      {
        error = error + e.getMessage() + " || ";
      }
    }

    if (error == null || error.isEmpty())
      return "Success";
    return "error = " + error + " || rolesNotFound = " + rolesNotFound;
  }

  public String modifyRoles( String roleNamesInCSV)
  {

    List roleNameList = Util.csvToList(roleNamesInCSV);
    List rolesNotFound = new ArrayList();
    String error = "";
    for (String roleName : roleNameList)
    {
      try
      {
        Bundle role = context.getObjectByName(Bundle.class, roleName);
        if (role == null)
        {
          rolesNotFound.add(roleName);
          continue;
        }
        role.setAttribute("appName", "AttestRCA");
        context.saveObject(role);
        context.commitTransaction();
      }
      catch (GeneralException e)
      {
        error = error + e.getMessage() + " || ";
      }
    }

    if (error == null || error.isEmpty())
      return "Success";
    return "error = " + error + " || rolesNotFound = " + rolesNotFound;
  }


